<!DOCTYPE html>
<html lang="nl" class="scroll-smooth">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>NØR. — Clarity in Flow</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&family=Syne:wght@400;500;700;800&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <link rel="icon" href="../assets/favicon.png" type="image/png">
    
    <script>
        tailwind.config = {
            theme: {
                extend: {
                    fontFamily: {
                        sans: ['Inter', 'sans-serif'],
                        display: ['Syne', 'sans-serif'],
                    },
                    colors: {
                        nor: {
                            deep: '#152238',
                            slate: '#3B4E68',
                            blue: '#5A738E',
                            dusty: '#96A9C1',
                            light: '#D0DBE5',
                            cream: '#F4F7F9',
                            accent: '#0B1320'
                        }
                    },
                    animation: {
                        'pulse-slow': 'pulse 6s cubic-bezier(0.4, 0, 0.6, 1) infinite',
                    }
                }
            }
        }
    </script>

    <style>
        body { cursor: none; background-color: #F4F7F9; overflow-x: hidden; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #F4F7F9; }
        ::-webkit-scrollbar-thumb { background: #96A9C1; border-radius: 10px; }
        ::-webkit-scrollbar-thumb:hover { background: #5A738E; }

        .custom-cursor {
            width: 20px; height: 20px;
            border: 1px solid rgba(21, 34, 56, 0.4);
            border-radius: 50%; position: fixed;
            transform: translate(-50%, -50%);
            pointer-events: none; z-index: 9999;
            transition: width 0.3s, height 0.3s, background-color 0.3s, border-color 0.3s;
        }
        .custom-cursor-dot {
            width: 4px; height: 4px;
            background-color: #152238; border-radius: 50%;
            position: fixed; transform: translate(-50%, -50%);
            pointer-events: none; z-index: 9999;
        }
        .topo-layer { transition: transform 0.15s ease-out; }
        .glassmorphic {
            background: rgba(244, 247, 249, 0.85);
            backdrop-filter: blur(16px);
            -webkit-backdrop-filter: blur(16px);
            border-bottom: 1px solid rgba(21, 34, 56, 0.06);
        }
        .organic-shape {
            border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%;
            animation: morph 12s ease-in-out infinite;
        }
        @keyframes morph {
            0%, 100% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
            25% { border-radius: 40% 60% 70% 30% / 40% 70% 30% 60%; }
            50% { border-radius: 50% 50% 40% 60% / 50% 40% 60% 50%; }
            75% { border-radius: 30% 70% 60% 40% / 70% 50% 50% 30%; }
        }
        .nav-link:hover .hover-bar, .nav-link:hover span { width: 100%; }
        .nav-link span { display: block; width: 0; height: 1px; background: #5A738E; transition: width 0.3s; }
        
        /* Lightbox styles */
        #lightbox {
            display: none; position: fixed; inset: 0;
            background: rgba(11,19,32,0.95); z-index: 10000;
            align-items: center; justify-content: center;
            backdrop-filter: blur(8px);
        }
        #lightbox.active { display: flex; }
        #lightbox img { max-width: 90vw; max-height: 90vh; object-fit: contain; border-radius: 12px; }
        
        /* Form focus states */
        input:focus, textarea:focus, select:focus {
            outline: none; border-color: #5A738E;
            box-shadow: 0 0 0 3px rgba(90,115,142,0.15);
        }

        /* Scroll animation */
        .reveal { opacity: 0; transform: translateY(30px); transition: opacity 0.7s ease, transform 0.7s ease; }
        .reveal.visible { opacity: 1; transform: translateY(0); }
    </style>
</head>
<body class="font-sans antialiased selection:bg-nor-blue selection:text-white">

    <div id="cursor" class="custom-cursor hidden md:block"></div>
    <div id="cursor-dot" class="custom-cursor-dot hidden md:block"></div>

    <!-- Lightbox -->
    <div id="lightbox" onclick="closeLightbox()">
        <img id="lightbox-img" src="" alt="">
        <button onclick="closeLightbox()" class="absolute top-6 right-8 text-white/70 hover:text-white text-3xl font-light leading-none">&times;</button>
    </div>

    <!-- Navigation -->
    <header class="fixed top-0 left-0 w-full z-50 glassmorphic px-6 py-4 md:px-12 md:py-5 flex justify-between items-center transition-all duration-300">
        <a href="#hero" class="group flex items-center gap-3">
            <svg class="w-8 h-8" viewBox="0 0 40 40" fill="none">
                <path d="M20 4 C10 4, 4 10, 4 20 C4 30, 10 36, 20 36 C30 36, 36 30, 36 20 C36 10, 30 4, 20 4Z" fill="#D0DBE5" opacity="0.6"/>
                <path d="M20 8 C12 8, 8 13, 8 20 C8 27, 12 32, 20 32 C28 32, 32 27, 32 20 C32 13, 28 8, 20 8Z" fill="#96A9C1" opacity="0.7"/>
                <path d="M20 12 C14 12, 11 16, 11 20 C11 24, 14 28, 20 28 C26 28, 29 24, 29 20 C29 16, 26 12, 20 12Z" fill="#5A738E" opacity="0.8"/>
                <path d="M20 16 C16 16, 14 18, 14 20 C14 22, 16 24, 20 24 C24 24, 26 22, 26 20 C26 18, 24 16, 20 16Z" fill="#3B4E68"/>
                <circle cx="20" cy="20" r="3" fill="#152238"/>
            </svg>
            <span class="font-display font-extrabold text-2xl tracking-[0.25em] text-nor-deep transition-all duration-300 group-hover:tracking-[0.35em]">NØR.</span>
        </a>
        
        <nav class="hidden md:flex items-center gap-10">
            <a href="#philosophy" class="nav-link text-xs uppercase tracking-[0.2em] text-nor-deep hover:text-nor-blue transition-colors duration-300 font-medium relative py-1">
                Philosophie<span></span>
            </a>
            <a href="#identity" class="nav-link text-xs uppercase tracking-[0.2em] text-nor-deep hover:text-nor-blue transition-colors duration-300 font-medium relative py-1">
                Ecosystem<span></span>
            </a>
            <a href="#playground" class="nav-link text-xs uppercase tracking-[0.2em] text-nor-deep hover:text-nor-blue transition-colors duration-300 font-medium relative py-1">
                Flow Studio<span></span>
            </a>
            <a href="#inquiry" class="nav-link text-xs uppercase tracking-[0.2em] text-nor-deep hover:text-nor-blue transition-colors duration-300 font-medium relative py-1">
                Contact<span></span>
            </a>
        </nav>

        <div class="flex items-center gap-4">
            <button id="audio-toggle" class="group relative flex items-center justify-center p-3 rounded-full bg-white border border-nor-light hover:border-nor-blue transition-all duration-300 shadow-sm" title="Ambient Flow Soundscape">
                <i id="audio-icon" class="fa-solid fa-volume-xmark text-nor-slate group-hover:text-nor-deep transition-colors duration-300 text-sm"></i>
            </button>
            <!-- Mobile menu button -->
            <button id="mobile-menu-btn" class="md:hidden p-3 rounded-full bg-white border border-nor-light">
                <i class="fa-solid fa-bars text-nor-deep text-sm"></i>
            </button>
            <a href="#inquiry" class="hidden md:block bg-nor-deep hover:bg-nor-blue text-white text-[10px] font-semibold tracking-[0.15em] uppercase px-5 py-3 rounded-full transition-all duration-300 shadow-md hover:shadow-lg hover:-translate-y-0.5">
                Inquire
            </a>
        </div>
    </header>

    <!-- Mobile Menu -->
    <div id="mobile-menu" class="hidden fixed inset-0 z-40 bg-nor-cream flex flex-col items-center justify-center gap-8 pt-20">
        <a href="#philosophy" onclick="closeMobileMenu()" class="font-display text-2xl tracking-widest uppercase text-nor-deep">Philosophie</a>
        <a href="#identity" onclick="closeMobileMenu()" class="font-display text-2xl tracking-widest uppercase text-nor-deep">Ecosystem</a>
        <a href="#playground" onclick="closeMobileMenu()" class="font-display text-2xl tracking-widest uppercase text-nor-deep">Flow Studio</a>
        <a href="#inquiry" onclick="closeMobileMenu()" class="font-display text-2xl tracking-widest uppercase text-nor-deep">Contact</a>
        <a href="#inquiry" onclick="closeMobileMenu()" class="mt-4 bg-nor-deep text-white text-xs font-bold tracking-[0.2em] uppercase px-8 py-4 rounded-full">Inquire</a>
    </div>

    <!-- Hero Section -->
    <section id="hero" class="relative min-h-screen w-full flex flex-col justify-center items-center px-6 md:px-12 py-32 overflow-hidden bg-nor-cream">
        <div class="absolute inset-0 z-0 flex justify-center items-center pointer-events-none select-none">
            <div class="topo-layer absolute w-[80vw] h-[80vw] max-w-[800px] max-h-[800px] bg-nor-light opacity-25 organic-shape" data-speed="1.2" style="animation-duration: 10s;"></div>
            <div class="topo-layer absolute w-[65vw] h-[65vw] max-w-[650px] max-h-[650px] bg-nor-dusty opacity-35 organic-shape" data-speed="2.4" style="animation-duration: 14s; animation-delay: -3s;"></div>
            <div class="topo-layer absolute w-[50vw] h-[50vw] max-w-[500px] max-h-[500px] bg-nor-blue opacity-40 organic-shape" data-speed="3.6" style="animation-duration: 18s; animation-delay: -6s;"></div>
            <div class="topo-layer absolute w-[35vw] h-[35vw] max-w-[350px] max-h-[350px] bg-nor-slate opacity-50 organic-shape" data-speed="4.8" style="animation-duration: 22s; animation-delay: -9s;"></div>
            <div class="topo-layer absolute w-[20vw] h-[20vw] max-w-[200px] max-h-[200px] bg-nor-deep opacity-70 organic-shape" data-speed="6.0" style="animation-duration: 26s; animation-delay: -12s;"></div>
        </div>

        <div class="relative z-10 text-center max-w-4xl px-4 flex flex-col items-center">
            <div class="flex items-center gap-3 mb-8">
                <span class="w-1.5 h-1.5 rounded-full bg-nor-blue animate-ping"></span>
                <p class="text-[10px] md:text-xs font-semibold uppercase tracking-[0.4em] text-nor-slate">Branding & Space Design Studio</p>
                <span class="w-1.5 h-1.5 rounded-full bg-nor-blue animate-ping"></span>
            </div>

            <!-- NOR Logo SVG matching actual brand -->
            <div class="mb-8 opacity-90">
                <svg viewBox="0 0 120 120" class="w-24 h-24 md:w-32 md:h-32 mx-auto drop-shadow-sm">
                    <path d="M60 8 C32 8, 10 30, 10 60 C10 90, 32 112, 60 112 C88 112, 110 90, 110 60 C110 30, 88 8, 60 8Z" fill="#D0DBE5" opacity="0.5"/>
                    <path d="M60 20 C38 20, 22 38, 22 60 C22 82, 38 100, 60 100 C82 100, 98 82, 98 60 C98 38, 82 20, 60 20Z" fill="#96A9C1" opacity="0.65"/>
                    <path d="M60 32 C44 32, 34 45, 34 60 C34 75, 44 88, 60 88 C76 88, 86 75, 86 60 C86 45, 76 32, 60 32Z" fill="#5A738E" opacity="0.75"/>
                    <path d="M60 44 C50 44, 44 52, 44 60 C44 68, 50 76, 60 76 C70 76, 76 68, 76 60 C76 52, 70 44, 60 44Z" fill="#3B4E68" opacity="0.9"/>
                    <ellipse cx="60" cy="60" rx="8" ry="8" fill="#152238"/>
                    <!-- Inner highlight dot -->
                    <circle cx="57" cy="57" r="2.5" fill="white" opacity="0.25"/>
                </svg>
            </div>

            <h1 class="font-display font-black text-6xl md:text-9xl text-nor-deep tracking-[0.2em] select-none leading-none mb-4 drop-shadow-sm">
                NØR<span class="text-nor-blue">.</span>
            </h1>
            <p class="font-display font-medium text-lg md:text-2xl text-nor-slate tracking-[0.3em] uppercase mb-8 select-none">
                Clarity in Flow
            </p>
            <p class="text-sm md:text-base text-nor-slate/80 max-w-lg mb-12 font-light leading-relaxed tracking-wide">
                Wij creëren minimalistische identiteiten, tactiel drukwerk en fysieke ruimtes die rust en structuur ademen. Geïnspireerd door organische contouren en de essentie van helderheid.
            </p>

            <div class="flex flex-col sm:flex-row items-center gap-4 w-full justify-center">
                <a href="#identity" class="bg-nor-deep hover:bg-nor-blue text-white text-xs font-bold tracking-[0.2em] uppercase px-8 py-4 rounded-full transition-all duration-300 w-full sm:w-auto shadow-lg hover:shadow-xl hover:-translate-y-0.5 text-center">
                    Explore Ecosystem
                </a>
                <a href="#playground" class="bg-white hover:bg-nor-cream text-nor-deep border border-nor-light text-xs font-bold tracking-[0.2em] uppercase px-8 py-4 rounded-full transition-all duration-300 w-full sm:w-auto shadow-sm text-center hover:-translate-y-0.5">
                    Tweak the Wave
                </a>
            </div>
        </div>

        <div class="absolute bottom-10 left-1/2 transform -translate-x-1/2 flex flex-col items-center gap-2 text-nor-slate/50 select-none">
            <span class="text-[10px] uppercase tracking-[0.3em] font-medium">Scroll down</span>
            <div class="w-[1px] h-12 bg-gradient-to-b from-nor-slate/50 to-transparent relative overflow-hidden">
                <div class="absolute top-0 left-0 w-full h-1/3 bg-nor-blue animate-bounce"></div>
            </div>
        </div>
    </section>

    <!-- Philosophy Section -->
    <section id="philosophy" class="relative py-24 md:py-36 bg-white overflow-hidden border-t border-nor-light">
        <div class="max-w-7xl mx-auto px-6 md:px-12 grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
            <div class="reveal">
                <span class="text-xs font-semibold tracking-[0.3em] uppercase text-nor-blue mb-4 block">Onze Visie</span>
                <h2 class="font-display font-bold text-3xl md:text-5xl text-nor-deep tracking-[0.1em] uppercase leading-tight mb-6">
                    De harmonie tussen gelaagdheid en leegte.
                </h2>
                <p class="text-nor-slate/80 text-sm md:text-base leading-relaxed mb-6 font-light">
                    Geïnspireerd door de organische en meanderende topografie van het Scandinavische landschap, brengt NØR structuur in complexiteit. Onze merkidentiteit — gedefinieerd door vloeiende overgangen en diepe, kalme tinten — vertaalt zich moeiteloos naar de fysieke en digitale wereld.
                </p>
                <p class="text-nor-slate/80 text-sm md:text-base leading-relaxed mb-8 font-light">
                    Van een minimalistische branding op milieuvriendelijk papier tot op maat gemaakte metalen waterflessen en sfeervolle posters: alles ademt dezelfde bezieling uit. Wij noemen dat <strong class="text-nor-deep font-medium">Clarity in Flow</strong>.
                </p>
                <div class="grid grid-cols-3 gap-4 pt-4 border-t border-nor-light">
                    <div>
                        <p class="font-display font-bold text-2xl text-nor-deep">100%</p>
                        <p class="text-[10px] text-nor-slate uppercase tracking-wider mt-1">Tactiel Ontwerp</p>
                    </div>
                    <div>
                        <p class="font-display font-bold text-2xl text-nor-deep">0.4s</p>
                        <p class="text-[10px] text-nor-slate uppercase tracking-wider mt-1">Vloeiende Flow</p>
                    </div>
                    <div>
                        <p class="font-display font-bold text-2xl text-nor-deep">Fine-art</p>
                        <p class="text-[10px] text-nor-slate uppercase tracking-wider mt-1">Premium Afwerking</p>
                    </div>
                </div>
            </div>

            <!-- Brand Guide Image (Image 2) -->
            <div class="reveal relative rounded-3xl overflow-hidden border border-nor-light shadow-xl cursor-pointer group" onclick="openLightbox('img2')">
                <img id="img2" src="data:image/png;base64," alt="NØR Brand Guidelines" class="w-full h-auto object-cover transition-transform duration-700 group-hover:scale-[1.03]">
                <div class="absolute inset-0 bg-gradient-to-t from-nor-deep/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 flex items-end p-6">
                    <div>
                        <p class="font-display text-white text-xl tracking-widest uppercase">Brand Guidelines</p>
                        <p class="text-white/70 text-xs mt-1">Klik om te vergroten</p>
                    </div>
                </div>
                <div class="absolute top-4 right-4 bg-white/90 backdrop-blur text-nor-deep text-[9px] font-bold tracking-widest uppercase px-3 py-1.5 rounded-full shadow opacity-0 group-hover:opacity-100 transition-opacity">
                    <i class="fa-solid fa-expand mr-1"></i> Bekijken
                </div>
            </div>
        </div>
    </section>

    <!-- Brand Ecosystem Section -->
    <section id="identity" class="relative py-24 md:py-36 bg-nor-cream overflow-hidden">
        <div class="max-w-7xl mx-auto px-6 md:px-12">
            <div class="text-center max-w-2xl mx-auto mb-16 md:mb-24 reveal">
                <span class="text-xs font-semibold tracking-[0.3em] uppercase text-nor-blue mb-4 block">The Physical Manifestation</span>
                <h2 class="font-display font-bold text-3xl md:text-5xl text-nor-deep tracking-[0.1em] uppercase mb-4">
                    Brand Ecosystem
                </h2>
                <p class="text-nor-slate/80 text-sm md:text-base leading-relaxed font-light">
                    Bekijk de fysieke identiteit en merchandise collectie van NØR. De rijke gelaagdheid is doorvertaald op hoogwaardige draagtassen, briefpapier, posters en alledaagse lifestyle-accessoires.
                </p>
            </div>

            <!-- Main Brand Image (Image 1) - Clickable Lightbox -->
            <div class="reveal relative bg-white p-4 md:p-8 rounded-3xl border border-nor-light shadow-xl overflow-hidden mb-16 cursor-pointer group" onclick="openLightbox('img1')">
                <div class="relative overflow-hidden rounded-2xl">
                    <img id="img1" src="data:image/png;base64," alt="NØR Brand Ecosystem Showcase" class="w-full h-auto object-cover transition-transform duration-1000 group-hover:scale-[1.02]">
                    <div class="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity duration-500 flex flex-col justify-end p-8 text-white">
                        <p class="font-display text-2xl tracking-widest uppercase mb-2">Physical Experience</p>
                        <p class="text-xs text-white/80 font-light max-w-md tracking-wider">Onze complete fysieke merchandise, briefpapier en verpakkingen weerspiegelen de pure identiteit van rust en structuur.</p>
                        <p class="text-xs text-white/60 mt-2"><i class="fa-solid fa-expand mr-1"></i> Klik om te vergroten</p>
                    </div>
                </div>
                <div class="absolute top-6 right-6 bg-nor-deep text-white text-[9px] font-bold tracking-widest uppercase px-4 py-2 rounded-full shadow-lg">
                    Real Brand Specimen
                </div>
            </div>

            <!-- Product Cards -->
            <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                <!-- Water Bottle -->
                <div class="reveal group bg-white rounded-2xl border border-nor-light p-6 shadow-sm hover:shadow-xl hover:-translate-y-1.5 transition-all duration-300 flex flex-col justify-between">
                    <div>
                        <div class="aspect-square w-full rounded-xl bg-nor-cream flex items-center justify-center mb-6 overflow-hidden relative">
                            <svg viewBox="0 0 120 180" class="w-24 h-36 drop-shadow-md">
                                <!-- Bottle body -->
                                <rect x="35" y="35" width="50" height="130" rx="10" fill="#152238"/>
                                <!-- Cap -->
                                <rect x="40" y="15" width="40" height="25" rx="6" fill="#8a8a8a"/>
                                <rect x="44" y="10" width="32" height="8" rx="4" fill="#aaa"/>
                                <!-- Logo mark on bottle -->
                                <g transform="translate(45, 55) scale(0.27)">
                                    <circle cx="55" cy="55" r="48" fill="#D0DBE5" opacity="0.3"/>
                                    <circle cx="55" cy="55" r="38" fill="#96A9C1" opacity="0.4"/>
                                    <circle cx="55" cy="55" r="28" fill="#5A738E" opacity="0.5"/>
                                    <circle cx="55" cy="55" r="18" fill="#3B4E68" opacity="0.7"/>
                                    <circle cx="55" cy="55" r="8" fill="#D0DBE5"/>
                                </g>
                                <!-- NOR text on bottle -->
                                <text x="60" y="135" fill="white" font-size="9" font-family="sans-serif" font-weight="bold" letter-spacing="2" text-anchor="middle">NØR.</text>
                                <text x="60" y="147" fill="white" font-size="5" font-family="sans-serif" letter-spacing="1.5" text-anchor="middle" opacity="0.6">CLARITY IN FLOW</text>
                                <!-- Shine -->
                                <rect x="40" y="40" width="8" height="60" rx="4" fill="white" opacity="0.05"/>
                            </svg>
                        </div>
                        <span class="text-[10px] uppercase tracking-widest text-nor-blue font-bold mb-1 block">Lifestyle</span>
                        <h3 class="font-display font-semibold text-lg text-nor-deep tracking-wide mb-2">The Flow Vessel</h3>
                    </div>
                    <p class="text-nor-slate/70 text-xs font-light mb-4">Matblauwe, dubbelwandige roestvrijstalen waterfles met geëtst organisch merkembleem.</p>
                    <button onclick="showSpec(this, 'Dubbelwandige RVS waterfles 500ml · Mat navy afwerking · Lasergeëtst NØR logo · BPA-vrij · Houd 12u koud / 8u warm')" class="text-xs text-nor-deep hover:text-nor-blue font-bold tracking-widest uppercase flex items-center gap-2 self-start transition-colors">
                        Specificaties <i class="fa-solid fa-arrow-right-long text-xs"></i>
                    </button>
                    <div class="spec-box hidden mt-3 p-3 bg-nor-cream rounded-xl text-xs text-nor-slate/80 font-light leading-relaxed border border-nor-light"></div>
                </div>

                <!-- Poster -->
                <div class="reveal group bg-white rounded-2xl border border-nor-light p-6 shadow-sm hover:shadow-xl hover:-translate-y-1.5 transition-all duration-300 flex flex-col justify-between">
                    <div>
                        <div class="aspect-square w-full rounded-xl bg-nor-cream flex items-center justify-center mb-6 overflow-hidden relative">
                            <div class="w-32 h-44 bg-white border-4 border-amber-800 rounded shadow-xl relative overflow-hidden p-3 flex flex-col justify-between -rotate-3 group-hover:rotate-0 transition-transform duration-500">
                                <div class="w-full flex-1 relative overflow-hidden rounded-sm">
                                    <!-- Mini topo pattern -->
                                    <svg viewBox="0 0 100 80" class="w-full h-full">
                                        <rect width="100" height="80" fill="#F4F7F9"/>
                                        <path d="M0,80 Q15,40 30,50 Q45,60 60,30 Q75,0 100,20 L100,80Z" fill="#D0DBE5" opacity="0.7"/>
                                        <path d="M0,80 Q20,55 40,60 Q60,65 80,40 Q90,25 100,35 L100,80Z" fill="#96A9C1" opacity="0.7"/>
                                        <path d="M0,80 Q25,65 50,68 Q70,70 90,55 L100,60 L100,80Z" fill="#5A738E" opacity="0.7"/>
                                        <path d="M0,80 Q30,72 60,74 Q80,76 100,70 L100,80Z" fill="#3B4E68" opacity="0.8"/>
                                    </svg>
                                </div>
                                <div class="mt-2 flex justify-between items-end">
                                    <div>
                                        <p class="text-[6px] tracking-widest font-black text-nor-deep leading-tight">CLARITY<br>IN FLOW</p>
                                    </div>
                                    <span class="text-[6px] font-black tracking-widest text-nor-deep">NØR.</span>
                                </div>
                            </div>
                        </div>
                        <span class="text-[10px] uppercase tracking-widest text-nor-blue font-bold mb-1 block">Interior</span>
                        <h3 class="font-display font-semibold text-lg text-nor-deep tracking-wide mb-2">Giclée Fine-Art Print</h3>
