        </div>
        <div class="max-w-7xl mx-auto px-6 md:px-12 pt-8 border-t border-white/5 flex flex-col sm:flex-row justify-between items-center gap-4">
            <p class="text-[10px] text-nor-dusty/50 tracking-wider">&copy; 2026 NØR. Studio. Alle rechten voorbehouden.</p>
            <p class="text-[10px] text-nor-dusty/50 tracking-wider">Ontworpen in harmonie met de natuur.</p>
        </div>
    </footer>

    <script>
        // ── Custom Cursor ──
        const cursor = document.getElementById('cursor');
        const cursorDot = document.getElementById('cursor-dot');
        document.addEventListener('mousemove', (e) => {
            cursor.style.left = e.clientX + 'px';
            cursor.style.top = e.clientY + 'px';
            cursorDot.style.left = e.clientX + 'px';
            cursorDot.style.top = e.clientY + 'px';
        });
        document.querySelectorAll('a, button, select, input, textarea').forEach(el => {
            el.addEventListener('mouseenter', () => {
                cursor.style.width = '40px'; cursor.style.height = '40px';
                cursor.style.backgroundColor = 'rgba(21,34,56,0.06)';
                cursor.style.borderColor = '#152238';
            });
            el.addEventListener('mouseleave', () => {
                cursor.style.width = '20px'; cursor.style.height = '20px';
                cursor.style.backgroundColor = 'transparent';
                cursor.style.borderColor = 'rgba(21,34,56,0.4)';
            });
        });

        // ── Parallax Topo Layers ──
        const topoLayers = document.querySelectorAll('.topo-layer');
        document.addEventListener('mousemove', (e) => {
            const x = (window.innerWidth / 2 - e.clientX) / 45;
            const y = (window.innerHeight / 2 - e.clientY) / 45;
            topoLayers.forEach(layer => {
                const speed = parseFloat(layer.getAttribute('data-speed'));
                layer.style.transform = `translate(${x * speed}px, ${y * speed}px)`;
            });
        });

        // ── Mobile Menu ──
        const mobileMenuBtn = document.getElementById('mobile-menu-btn');
        const mobileMenu = document.getElementById('mobile-menu');
        mobileMenuBtn.addEventListener('click', () => {
            mobileMenu.classList.toggle('hidden');
            mobileMenu.classList.toggle('flex');
        });
        function closeMobileMenu() {
            mobileMenu.classList.add('hidden');
            mobileMenu.classList.remove('flex');
        }

        // ── Lightbox ──
        function openLightbox(imgId) {
            const lb = document.getElementById('lightbox');
            const lbImg = document.getElementById('lightbox-img');
            lbImg.src = document.getElementById(imgId).src;
            lb.classList.add('active');
            document.body.style.overflow = 'hidden';
        }
        function closeLightbox() {
            document.getElementById('lightbox').classList.remove('active');
            document.body.style.overflow = '';
        }
        document.addEventListener('keydown', e => { if(e.key === 'Escape') closeLightbox(); });

        // ── Spec boxes ──
        function showSpec(btn, text) {
            const box = btn.nextElementSibling;
            if (box.classList.contains('hidden')) {
                box.textContent = text;
                box.classList.remove('hidden');
                btn.innerHTML = 'Verbergen <i class="fa-solid fa-arrow-up text-xs"></i>';
            } else {
                box.classList.add('hidden');
                btn.innerHTML = 'Specificaties <i class="fa-solid fa-arrow-right-long text-xs"></i>';
            }
        }

        // ── Ambient Sound (Web Audio API) ──
        let audioContext = null, isPlaying = false;
        let oscillators = [], gainNodes = [];
        const audioToggle = document.getElementById('audio-toggle');
        const audioIcon = document.getElementById('audio-icon');

        function startAudio() {
            audioContext = audioContext || new (window.AudioContext || window.webkitAudioContext)();
            const masterGain = audioContext.createGain();
            masterGain.gain.setValueAtTime(0, audioContext.currentTime);
            masterGain.gain.linearRampToValueAtTime(0.3, audioContext.currentTime + 3);
            masterGain.connect(audioContext.destination);

            // Reverb via convolver
            const convolver = audioContext.createConvolver();
            const bufLen = audioContext.sampleRate * 2;
            const impulse = audioContext.createBuffer(2, bufLen, audioContext.sampleRate);
            for(let ch = 0; ch < 2; ch++) {
                const d = impulse.getChannelData(ch);
                for(let i = 0; i < bufLen; i++) d[i] = (Math.random() * 2 - 1) * Math.pow(1 - i/bufLen, 2);
            }
            convolver.buffer = impulse;
            convolver.connect(masterGain);

            const freqs = [110, 165, 220, 330, 440];
            freqs.forEach((f, i) => {
                const osc = audioContext.createOscillator();
                const g = audioContext.createGain();
                const lfo = audioContext.createOscillator();
                const lfoGain = audioContext.createGain();
                osc.type = i % 2 === 0 ? 'sine' : 'triangle';
                osc.frequency.value = f;
                lfo.frequency.value = 0.1 + i * 0.05;
                lfoGain.gain.value = 1.5;
                lfo.connect(lfoGain); lfoGain.connect(osc.frequency);
                g.gain.value = 0.03 / freqs.length;
                osc.connect(g); g.connect(convolver);
                osc.start(); lfo.start();
                oscillators.push(osc, lfo);
                gainNodes.push(g, masterGain);
            });
        }

        function stopAudio() {
            gainNodes.forEach(g => {
                try { g.gain.linearRampToValueAtTime(0, audioContext.currentTime + 1.5); } catch(e){}
            });
            setTimeout(() => { oscillators.forEach(o => { try { o.stop(); } catch(e){} }); oscillators = []; gainNodes = []; }, 1600);
        }

        audioToggle.addEventListener('click', () => {
            isPlaying = !isPlaying;
            if (isPlaying) {
                startAudio();
                audioIcon.className = 'fa-solid fa-volume-high text-sm';
                audioIcon.style.color = '#5A738E';
                audioToggle.style.borderColor = '#5A738E';
            } else {
                stopAudio();
                audioIcon.className = 'fa-solid fa-volume-xmark text-sm text-nor-slate';
                audioIcon.style.color = '';
                audioToggle.style.borderColor = '';
            }
        });

        // ── Wave Canvas ──
        const canvas = document.getElementById('flow-canvas');
        const ctx = canvas.getContext('2d');

        function resizeCanvas() {
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
        }
        resizeCanvas();
        window.addEventListener('resize', resizeCanvas);

        const ampSlider = document.getElementById('amp-slider');
        const freqSlider = document.getElementById('freq-slider');
        const speedSlider = document.getElementById('speed-slider');
        const layersSlider = document.getElementById('layers-slider');

        const palettes = {
            classic: ['rgba(208,219,229,0.85)','rgba(150,169,193,0.85)','rgba(90,115,142,0.85)','rgba(59,78,104,0.85)','rgba(21,34,56,0.9)','rgba(11,19,32,0.95)','rgba(5,10,18,1)','rgba(2,5,9,1)'],
            deep: ['rgba(91,192,190,0.8)','rgba(58,80,107,0.85)','rgba(28,37,65,0.88)','rgba(11,19,32,0.9)','rgba(5,10,18,0.95)','rgba(3,6,12,0.97)','rgba(1,3,8,1)','rgba(0,1,4,1)'],
            light: ['rgba(240,244,248,0.8)','rgba(208,219,229,0.85)','rgba(164,179,198,0.85)','rgba(150,169,193,0.88)','rgba(90,115,142,0.9)','rgba(59,78,104,0.92)','rgba(40,58,84,0.95)','rgba(21,34,56,1)']
        };
        let currentPalette = 'classic';
        let offset = 0;

        function setPalette(btn, name) {
            currentPalette = name;
            document.querySelectorAll('.palette-btn').forEach(b => {
                b.className = 'palette-btn px-4 py-2 rounded-full border border-white/20 hover:border-white text-[10px] uppercase tracking-wider font-semibold text-white hover:bg-white/10 transition-all duration-300';
            });
            btn.className = 'palette-btn active-palette px-4 py-2 rounded-full border border-white text-[10px] uppercase tracking-wider font-semibold bg-white text-nor-accent transition-all duration-300';
        }

        function drawWaves() {
            const w = canvas.width, h = canvas.height;
            ctx.clearRect(0, 0, w, h);

            const amp = parseInt(ampSlider.value);
            const freq = parseInt(freqSlider.value) * 0.001;
            const speed = parseInt(speedSlider.value) * 0.001;
            const layers = parseInt(layersSlider.value);

            document.getElementById('amp-val').textContent = amp;
            document.getElementById('freq-val').textContent = (freq).toFixed(3);
            document.getElementById('speed-val').textContent = (speed).toFixed(3);
            document.getElementById('layers-val').textContent = layers;

            const colors = palettes[currentPalette];

            for (let l = 0; l < layers; l++) {
                const t = l / layers;
                const baseY = h * (0.3 + t * 0.6);
                const phaseOffset = l * (Math.PI * 2 / layers) * 1.3;
                const layerAmp = amp * (1 - t * 0.3);

                ctx.beginPath();
                ctx.moveTo(0, h);
                ctx.lineTo(0, baseY + Math.sin(phaseOffset + offset) * layerAmp);

                for (let x = 0; x <= w; x += 2) {
                    const y = baseY + Math.sin(x * freq + offset + phaseOffset) * layerAmp
                             + Math.sin(x * freq * 2.1 + offset * 1.3 + phaseOffset) * (layerAmp * 0.3);
                    ctx.lineTo(x, y);
                }
                ctx.lineTo(w, h);
                ctx.closePath();
                ctx.fillStyle = colors[Math.min(l, colors.length - 1)];
                ctx.fill();
            }

            offset += speed;
            requestAnimationFrame(drawWaves);
        }
        drawWaves();

        // ── Contact Form ──
        function submitForm() {
            const name = document.getElementById('f-name').value.trim();
            const email = document.getElementById('f-email').value.trim();
            const msg = document.getElementById('f-msg').value.trim();
            const errBox = document.getElementById('form-error');

            if (!name || !email || !msg) {
                errBox.textContent = 'Vul alle verplichte velden in (naam, e-mail en projectbeschrijving).';
                errBox.classList.remove('hidden');
                return;
            }
            if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
                errBox.textContent = 'Voer een geldig e-mailadres in.';
                errBox.classList.remove('hidden');
                return;
            }
            errBox.classList.add('hidden');
            document.getElementById('form-wrap').style.opacity = '0.4';
            document.getElementById('form-wrap').style.pointerEvents = 'none';
            setTimeout(() => {
                document.getElementById('form-wrap').classList.add('hidden');
                document.getElementById('form-success').classList.remove('hidden');
            }, 800);
        }

        // ── Scroll Reveal ──
        const revealEls = document.querySelectorAll('.reveal');
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                    observer.unobserve(entry.target);
                }
            });
        }, { threshold: 0.1, rootMargin: '0px 0px -50px 0px' });
        revealEls.forEach(el => observer.observe(el));

        // ── Smooth scroll ──
        document.querySelectorAll('a[href^="#"]').forEach(a => {
            a.addEventListener('click', e => {
                const target = document.querySelector(a.getAttribute('href'));
                if (target) { e.preventDefault(); target.scrollIntoView({ behavior: 'smooth' }); }
            });
        });
    </script>
</body>
</html>